              <div>
                <h2 className="text-2xl font-bold text-gray-800 capitalize">
                  {NAV_ITEMS.find(n => n.id === activeTab)?.label}
                </h2>
                <p className="text-sm text-gray-500 mt-1">
                  Vista general y gestión de {NAV_ITEMS.find(n => n.id === activeTab)?.label}
