import React, { useState, useEffect, useMemo } from 'react';
import { GoogleGenAI } from "@google/genai";
import { fetchDigest, createResource } from '../services/api';
import { NewsItem } from '../types';
import { 
  Zap, 
  RefreshCw, 
  ExternalLink, 
  BrainCircuit, 
  Loader2, 
  X,
  FileJson,
  CheckCircle2,
  AlertCircle,
  Save,
  ShieldAlert,
  Globe,
  Sparkles,
  Search,
  BookOpenCheck,
  Flame,
  Clock,
  LayoutGrid,
  List,
  TriangleAlert
} from 'lucide-react';
import { marked } from 'marked';

export const IntelligenceDigest: React.FC = () => {
  const [items, setItems] = useState<NewsItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // AI States
  const [summary, setSummary] = useState<string | null>(null);
  const [summarizing, setSummarizing] = useState(false);

  // Triage States
  const [urlInput, setUrlInput] = useState("");
  const [analyzing, setAnalyzing] = useState(false);
  const [detectedType, setDetectedType] = useState<string | null>(null);
  const [formData, setFormData] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [showModal, setShowModal] = useState(false);

  // Check API KEY safely to prevent crash on instantiation
  const apiKey = process.env.API_KEY;
  const ai = useMemo(() => {
    if (!apiKey || apiKey === 'undefined') return null;
    return new GoogleGenAI({ apiKey });
  }, [apiKey]);

  const loadData = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await fetchDigest(3);
      setItems(data || []);
    } catch (err) {
      console.error("Error fetching digest:", err);
      setError("No se pudo conectar con el servidor para obtener las noticias.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const generateBriefSummary = async (newsItems: NewsItem[]) => {
    if (!ai) {
      alert("Error: No se ha detectado la API_KEY de Gemini.");
      return;
    }
    if (newsItems.length === 0) return;

    setSummarizing(true);
    try {
      const newsContent = newsItems.slice(0, 10).map(item => `- [${item.feedTitle}] ${item.title}: ${item.description?.substring(0, 150)}`).join('\n');
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Act like a Senior CTI Analyst. Summarize the following news list into a concise executive daily brief. Focus on emerging threats, critical vulnerabilities, and global campaigns. Use markdown with sections for "Top Threats", "Vulnerabilities", and "Recommended Actions".\n\nNews:\n${newsContent}`,
      });
      setSummary(response.text || "No se pudo generar el resumen.");
    } catch (error) {
      console.error("Summary error:", error);
      setSummary("Error al generar el resumen ejecutivo. Verifica tu cuota de API o conexión.");
    } finally {
      setSummarizing(false);
    }
  };

  const handleAnalizar = async (url: string, newsItem?: NewsItem) => {
    if (!ai) {
      alert("Configura la API_KEY para usar el triaje inteligente.");
      return;
    }
    setAnalyzing(true);
    setShowModal(true);
    setFormData(null);
    setDetectedType(null);

    try {
      const context = newsItem ? `Title: ${newsItem.title}\nDescription: ${newsItem.description}\nSource: ${newsItem.feedTitle}` : `URL: ${url}`;
      const prompt = `Act as a CTI Triage Engine. Analyze this intelligence source and map it to one of these types: 'incidente', 'exploit', 'zeroday', 'cve', or 'alerta'. 
      Return ONLY a JSON object with two fields: "type" (one of the strings above) and "data" (the mapped object following these rules:
      - incidente: { fecha (YYYY-MM-DD), tipo, entidad, pais, sector, descripcion, actor, url }
      - exploit: { fecha, nombre, tipo, plataforma, cve, url }
      - zeroday: { idZD, fecha, nombre, plataforma, cvss, estado, url, descripcion }
      - cve: { cveId, fecha, aplicativo, cvss, estado, descripcion, url }
      - alerta: { titulo, descripcion, criticidad (Baja/Media/Alta/Critica), fecha, url }
      )
      Context:\n${context}`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      const text = response.text;
      if (!text) throw new Error("Empty AI response");

      const result = JSON.parse(text);
      setDetectedType(result.type);
      setFormData(result.data);
    } catch (err: any) {
      console.error("Triage Error:", err);
      setFormData({ error: "Error de análisis: La IA no pudo estructurar los datos de esta fuente correctamente." });
    } finally {
      setAnalyzing(false);
    }
  };

  const handleFieldChange = (key: string, value: any) => {
    setFormData((prev: any) => prev ? ({ ...prev, [key]: value }) : null);
  };

  const handleSaveResource = async () => {
    if (!detectedType || !formData) return;
    setIsSaving(true);
    try {
      const res = await createResource(detectedType, formData);
      if (res.success) {
        setShowModal(false);
        setFormData(null);
        setDetectedType(null);
        setUrlInput("");
        loadData();
      } else {
        alert("Error al guardar en base de datos: " + res.message);
      }
    } catch (err) {
      console.error("Save Error:", err);
      alert("Error crítico al intentar guardar el recurso.");
    } finally {
      setIsSaving(false);
    }
  };

  const renderMarkdown = (text: string | null) => {
    if (!text) return "";
    try {
      return marked.parse(text) as string;
    } catch (e) {
      return text;
    }
  };

  if (!apiKey || apiKey === 'undefined') {
    return (
      <div className="flex flex-col items-center justify-center p-20 text-center bg-amber-50 rounded-3xl border-2 border-dashed border-amber-200">
        <TriangleAlert className="w-16 h-16 text-amber-500 mb-4" />
        <h2 className="text-2xl font-black text-amber-900 mb-2">Clave de API Faltante</h2>
        <p className="text-amber-700 max-w-md">
          Para utilizar el Intelligence Hub con IA, debes configurar la variable de entorno <strong>API_KEY</strong> con tu clave de Google Gemini.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-8 pb-12">
      {/* Search & Triage Header */}
      <div className="bg-gradient-to-r from-slate-900 via-indigo-950 to-slate-900 text-white p-10 rounded-3xl shadow-2xl border border-indigo-500/30 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
            <BrainCircuit className="w-64 h-64" />
        </div>

        <div className="relative z-10 max-w-4xl">
            <div className="flex items-center gap-3 mb-4">
              <span className="bg-indigo-500/20 text-indigo-300 text-[10px] font-black uppercase tracking-[0.2em] px-3 py-1 rounded-full border border-indigo-500/30">
                SATI ENGINE v4.2
              </span>
            </div>
            <h2 className="text-4xl font-black mb-4 flex items-center gap-3 tracking-tight">
                <Zap className="w-10 h-10 text-amber-400 fill-amber-400" />
                Intelligence Hub
            </h2>
            <p className="text-slate-400 mb-8 text-lg leading-relaxed">
                Triaje automatizado y síntesis de inteligencia estratégica mediante modelos Gemini 3.
            </p>

            <form 
              onSubmit={(e) => { e.preventDefault(); handleAnalizar(urlInput); }}
              className="flex flex-col md:flex-row gap-4"
            >
                <div className="relative flex-1 group">
                    <Globe className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500 group-focus-within:text-amber-500 transition-colors" />
                    <input 
                        type="url"
                        placeholder="Ingresa URL para triaje (DarkReading, BleepingComputer, CVE...)"
                        value={urlInput}
                        onChange={(e) => setUrlInput(e.target.value)}
                        className="w-full pl-14 pr-6 py-5 bg-slate-800/50 border border-slate-700 rounded-2xl focus:ring-2 focus:ring-amber-500 outline-none text-slate-100 placeholder:text-slate-600 transition-all font-medium backdrop-blur-sm"
                        required
                    />
                </div>
                <button 
                    type="submit"
                    disabled={analyzing || !urlInput}
                    className="px-10 py-5 bg-amber-500 hover:bg-amber-600 text-slate-950 font-black rounded-2xl shadow-xl shadow-amber-900/40 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
                >
                    {analyzing ? <Loader2 className="w-6 h-6 animate-spin" /> : <Search className="w-6 h-6" />}
                    Analizar Fuente
                </button>
            </form>
        </div>
      </div>

      {/* AI Brief Section */}
      <div className="bg-white rounded-3xl border border-indigo-100 shadow-xl overflow-hidden">
        <div className="p-8 border-b border-indigo-50 flex justify-between items-center bg-indigo-50/30">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl">
              <Sparkles className="w-5 h-5 text-white" />
            </div>
            <div>
              <h3 className="text-xl font-bold text-slate-800">Brief Ejecutivo Diario</h3>
              <p className="text-sm text-slate-500">Resumen sintetizado por el Agente de Inteligencia</p>
            </div>
          </div>
          <button 
            onClick={() => generateBriefSummary(items)}
            disabled={summarizing || items.length === 0}
            className="flex items-center gap-2 px-6 py-2.5 bg-indigo-600 text-white rounded-xl text-sm font-bold hover:bg-indigo-700 transition-all disabled:opacity-50 shadow-lg shadow-indigo-100"
          >
            {summarizing ? <Loader2 className="w-4 h-4 animate-spin" /> : <BookOpenCheck className="w-4 h-4" />}
            {summary ? 'Actualizar Brief' : 'Generar Daily Brief'}
          </button>
        </div>

        <div className="p-8">
          {summarizing ? (
            <div className="flex flex-col items-center justify-center py-12 gap-4">
              <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-500 rounded-full animate-spin"></div>
              <p className="text-slate-500 font-medium italic">Sintetizando inteligencia estratégica...</p>
            </div>
          ) : summary ? (
            <div className="prose prose-indigo max-w-none animate-in fade-in duration-500">
              <div 
                className="bg-indigo-50/20 p-8 rounded-2xl border border-indigo-100 font-sans text-slate-800 leading-relaxed text-base"
                dangerouslySetInnerHTML={{ __html: renderMarkdown(summary) }}
              />
            </div>
          ) : (
            <div className="text-center py-12 text-slate-400 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
              <Sparkles className="w-16 h-16 mx-auto mb-3 opacity-20" />
              <p className="font-medium">El Daily Brief sintetiza los feeds recientes para destacar lo más crítico.</p>
            </div>
          )}
        </div>
      </div>

      {/* Discovery Feed Section */}
      <div className="space-y-6">
        <div className="flex justify-between items-center px-2">
            <div className="flex items-center gap-3">
              <h3 className="text-2xl font-black text-slate-800 tracking-tight flex items-center gap-3">
                  <Flame className="w-6 h-6 text-orange-500 fill-orange-500" />
                  CTI Observatory
              </h3>
              <span className="bg-slate-100 text-slate-500 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider">
                Live Feed
              </span>
            </div>
            <div className="flex items-center gap-2 bg-slate-100 p-1 rounded-xl border border-slate-200">
              <button 
                onClick={() => setViewMode('grid')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}
              >
                <LayoutGrid className="w-4 h-4" />
              </button>
              <button 
                onClick={() => setViewMode('list')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'list' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}
              >
                <List className="w-4 h-4" />
              </button>
              <div className="w-px h-4 bg-slate-200 mx-1"></div>
              <button 
                onClick={loadData}
                disabled={loading}
                className="p-2 text-slate-500 hover:text-indigo-600 transition-colors"
              >
                <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
              </button>
            </div>
        </div>

        {loading ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {[1,2,3,4,5,6].map(i => (
                  <div key={i} className="bg-white h-64 rounded-2xl animate-pulse border border-slate-100 shadow-sm"></div>
                ))}
            </div>
        ) : error ? (
            <div className="p-10 bg-red-50 text-red-700 rounded-3xl border border-red-200 text-center">
                <AlertCircle className="w-12 h-12 mx-auto mb-3" />
                <p className="font-bold">{error}</p>
                <button onClick={loadData} className="mt-4 px-6 py-2 bg-red-100 hover:bg-red-200 rounded-xl transition-all">Reintentar</button>
            </div>
        ) : (
            <div className={viewMode === 'grid' ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6" : "space-y-4"}>
                {items.map((item, idx) => (
                    <div key={idx} className={`bg-white rounded-2xl border border-slate-200 overflow-hidden hover:shadow-2xl hover:border-indigo-300 transition-all flex flex-col group relative ${viewMode === 'list' ? 'flex-row items-center gap-6 p-4' : ''}`}>
                        <div className={viewMode === 'grid' ? "p-6 flex-1" : "flex-1"}>
                            <div className="flex justify-between items-center mb-4">
                                <span className="px-2.5 py-1 bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase rounded-lg tracking-wider border border-indigo-100">
                                    {item.feedTitle}
                                </span>
                                <div className="flex items-center gap-1.5 text-[10px] text-slate-400 font-bold uppercase">
                                  <Clock className="w-3 h-3" />
                                  {new Date(item.pubDate).toLocaleDateString()}
                                </div>
                            </div>
                            <h4 className="font-bold text-slate-900 leading-snug mb-3 line-clamp-2 group-hover:text-indigo-600 transition-colors text-lg">
                                {item.title}
                            </h4>
                            <p className="text-sm text-slate-500 line-clamp-2 leading-relaxed font-medium">
                                {item.description?.replace(/<[^>]*>?/gm, '') || 'Sin descripción disponible.'}
                            </p>
                        </div>
                        <div className={viewMode === 'grid' ? "px-6 py-4 bg-slate-50 border-t border-slate-100 flex items-center justify-between" : "flex flex-col gap-2"}>
                            <a 
                              href={item.link} 
                              target="_blank" 
                              rel="noreferrer" 
                              className="text-slate-400 hover:text-indigo-600 p-2 hover:bg-white rounded-xl transition-all"
                              title="Ver Fuente Original"
                            >
                                <ExternalLink className="w-5 h-5" />
                            </a>
                            <button 
                                onClick={() => handleAnalizar(item.link, item)}
                                className="px-5 py-2.5 bg-slate-900 text-white text-[11px] font-black rounded-xl hover:bg-indigo-600 transition-all flex items-center gap-2 shadow-lg shadow-slate-200"
                            >
                                <Zap className="w-3.5 h-3.5 text-amber-400 fill-amber-400" />
                                Triaje IA
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        )}
      </div>

      {/* Triage Review Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-950/80 z-50 flex items-center justify-center p-4 backdrop-blur-md">
            <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col animate-in fade-in zoom-in duration-500 overflow-hidden border border-slate-100">
                <div className="flex justify-between items-center p-8 border-b border-slate-100 bg-slate-50/50">
                    <div className="flex items-center gap-5">
                        <div className="bg-amber-500 p-3.5 rounded-3xl shadow-xl shadow-amber-200/50">
                            <BrainCircuit className="w-8 h-8 text-white" />
                        </div>
                        <div>
                            <h3 className="text-2xl font-black text-slate-900 tracking-tight">SATI Triage Engine</h3>
                            <div className="flex items-center gap-2 mt-1">
                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Status:</span>
                                <span className={`text-[10px] font-black uppercase px-3 py-1 rounded-full border ${analyzing ? 'bg-amber-50 text-amber-700 border-amber-200 animate-pulse' : 'bg-green-50 text-green-700 border-green-200'}`}>
                                    {analyzing ? 'Processing LLM...' : 'Verified Intelligence'}
                                </span>
                            </div>
                        </div>
                    </div>
                    {!analyzing && (
                        <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-900 p-3 hover:bg-slate-100 rounded-full transition-all">
                            <X className="w-8 h-8" />
                        </button>
                    )}
                </div>

                <div className="flex-1 overflow-y-auto p-10 bg-slate-50/30">
                    {analyzing ? (
                        <div className="h-full flex flex-col items-center justify-center text-center py-20 animate-in fade-in duration-500">
                            <div className="relative mb-10">
                                <div className="w-32 h-32 border-[6px] border-amber-100 border-t-amber-500 rounded-full animate-spin"></div>
                                <Zap className="w-14 h-14 text-amber-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 fill-current drop-shadow-lg" />
                            </div>
                            <h4 className="text-3xl font-black text-slate-900 mb-3 tracking-tight">Analizando Datos Semánticos</h4>
                            <p className="text-slate-500 max-w-sm mx-auto text-lg leading-relaxed">Gemini está mapeando la información según el esquema de inteligencia...</p>
                        </div>
                    ) : formData ? (
                        <div className="space-y-10">
                            {formData.error ? (
                                <div className="p-10 text-center text-red-500 bg-red-50 rounded-3xl border border-red-100">
                                    <AlertCircle className="w-12 h-12 mx-auto mb-4" />
                                    <p className="font-bold text-lg">{formData.error}</p>
                                </div>
                            ) : (
                                <>
                                    <div className="flex items-center justify-between bg-white p-5 rounded-2xl border border-slate-100 shadow-sm">
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 bg-green-100 rounded-xl">
                                                <CheckCircle2 className="w-6 h-6 text-green-600" />
                                            </div>
                                            <h4 className="font-black text-slate-800 uppercase tracking-tight text-sm">
                                              Registro detectado: <span className="text-indigo-600 font-black">{detectedType?.toUpperCase()}</span>
                                            </h4>
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8 bg-white p-10 rounded-[2rem] border border-slate-200 shadow-xl shadow-slate-200/50 relative overflow-hidden">
                                        <div className="absolute top-0 left-0 w-3 h-full bg-indigo-500"></div>
                                        {Object.keys(formData).map((key) => (
                                            <div key={key} className={key === 'descripcion' ? 'md:col-span-2' : ''}>
                                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">
                                                    {key.replace(/([A-Z])/g, ' $1').trim()}
                                                </label>
                                                {key === 'descripcion' ? (
                                                    <textarea 
                                                        value={formData[key]}
                                                        onChange={(e) => handleFieldChange(key, e.target.value)}
                                                        className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl text-base font-semibold text-slate-700 focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 focus:bg-white outline-none min-h-[160px] transition-all resize-none shadow-inner"
                                                    />
                                                ) : (
                                                    <input 
                                                        type={key === 'fecha' ? 'date' : (typeof formData[key] === 'number' ? 'number' : 'text')}
                                                        value={formData[key]}
                                                        onChange={(e) => handleFieldChange(key, e.target.value)}
                                                        className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl text-base font-bold text-slate-800 focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 focus:bg-white outline-none transition-all shadow-inner"
                                                    />
                                                )}
                                            </div>
                                        ))}
                                    </div>

                                    <div className="bg-slate-900 p-8 rounded-[2rem] flex items-start gap-5 shadow-2xl">
                                        <ShieldAlert className="w-10 h-10 text-amber-500 mt-1 flex-shrink-0" />
                                        <div>
                                            <p className="font-black text-white text-lg mb-2">Validación Final</p>
                                            <p className="text-slate-400 text-sm leading-relaxed font-medium">
                                              Verifica que los datos detectados sean precisos antes de registrar en el sistema central.
                                            </p>
                                        </div>
                                    </div>
                                </>
                            )}
                        </div>
                    ) : null}
                </div>

                <div className="p-8 border-t border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-6">
                    <div className="flex items-center gap-3 text-xs font-black text-slate-400 uppercase tracking-widest">
                        <FileJson className="w-5 h-5 text-indigo-500" />
                        SATI_ENGINE_ID: {Math.random().toString(36).substring(7).toUpperCase()}
                    </div>
                    <div className="flex gap-4 w-full md:w-auto">
                        <button 
                            onClick={() => setShowModal(false)}
                            className="flex-1 md:flex-none px-10 py-4 text-slate-500 font-black hover:bg-slate-50 rounded-2xl transition-all border border-slate-200 hover:border-slate-300 active:scale-95"
                        >
                            Cancelar
                        </button>
                        <button 
                            onClick={handleSaveResource}
                            disabled={isSaving || !formData || formData.error}
                            className="flex-1 md:flex-none px-14 py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-2xl shadow-2xl shadow-indigo-300 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
                        >
                            {isSaving ? <Loader2 className="w-6 h-6 animate-spin" /> : <Save className="w-6 h-6" />}
                            Registrar Inteligencia
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

