  const [analyzing, setAnalyzing] = useState(false);
  const [detectedType, setDetectedType] = useState<string | null>(null);
  const [formData, setFormData] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [apiKeyError, setApiKeyError] = useState(false);

  const loadData = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await fetchDigest(3);
      setItems(data || []);
    } catch (err) {
      console.error("Error fetching digest:", err);
      setError("No se pudo conectar con el servidor de inteligencia.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
    // Check if API_KEY is present
    const key = process.env.API_KEY;
    if (!key || key === 'undefined') {
      setApiKeyError(true);
    }
  }, []);

  const handleGenerateBrief = async () => {
    if (items.length === 0) return;
    setSummarizing(true);
    try {
      const result = await generateStrategicBriefAI(items);
      setSummary(result || "La IA no devolvió contenido.");
    } catch (error: any) {
      console.error("Summary error:", error);
      if (error.message === 'API_KEY_MISSING') setApiKeyError(true);
      else setSummary(`Error de síntesis: ${error.message || 'Verifica tu conexión.'}`);
    } finally {
      setSummarizing(false);
    }
  };

  const handleAnalizar = async (url: string, newsItem?: NewsItem) => {
    setAnalyzing(true);
    setShowModal(true);
    setFormData(null);
    setDetectedType(null);

    try {
      const context = newsItem ? `Title: ${newsItem.title}\nDescription: ${newsItem.description}\nSource: ${newsItem.feedTitle}` : `URL: ${url}`;
      const result = await performIntelligenceTriageAI(url, context);
      setDetectedType(result.type);
      setFormData(result.data);
    } catch (err: any) {
      console.error("Triage Error:", err);
      if (err.message === 'API_KEY_MISSING') setApiKeyError(true);
      else setFormData({ error: "Error de análisis semántico. La IA no pudo estructurar esta fuente." });
    } finally {
      setAnalyzing(false);
    }
  };

  const handleFieldChange = (key: string, value: any) => {
    setFormData((prev: any) => prev ? ({ ...prev, [key]: value }) : null);
  };

  const handleSaveResource = async () => {
    if (!detectedType || !formData) return;
    setIsSaving(true);
    try {
      const res = await createResource(detectedType, formData);
      if (res.success) {
        setShowModal(false);
        setFormData(null);
        setDetectedType(null);
        setUrlInput("");
        loadData();
      } else {
        alert("Error al registrar: " + res.message);
      }
    } catch (err) {
      console.error("Save Error:", err);
      alert("Error crítico al guardar en base de datos.");
    } finally {
      setIsSaving(false);
    }
  };

  const renderMarkdown = (text: string | null): string => {
    if (!text) return "";
    try {
      const m = marked as any;
      if (m && typeof m.parse === 'function') return m.parse(text);
      if (typeof m === 'function') return m(text);
      return text;
    } catch (e) {
      return text;
    }
  };

  if (apiKeyError) {
    return (
      <div className="flex flex-col items-center justify-center p-12 md:p-24 text-center bg-white rounded-[3rem] border-4 border-dashed border-slate-100 min-h-[500px] shadow-inner">
        <div className="bg-amber-50 p-6 rounded-full mb-8">
          <ShieldQuestion className="w-16 h-16 text-amber-500" />
        </div>
        <h2 className="text-3xl font-black text-slate-800 mb-4 tracking-tight">Intelligence Hub en Espera</h2>
        <p className="text-slate-500 max-w-md leading-relaxed mb-10 text-lg">
          Para activar las capacidades de IA, síntesis estratégica y triaje automático, configura la <strong>API_KEY</strong> de Google Gemini.
        </p>
        <div className="flex flex-col sm:flex-row gap-4">
            <button 
              onClick={() => { setApiKeyError(false); loadData(); }}
              className="flex items-center justify-center gap-3 px-8 py-4 bg-slate-900 text-white rounded-2xl font-black hover:bg-slate-800 transition-all shadow-xl active:scale-95"
            >
              <RefreshCw className="w-5 h-5" /> Reintentar Conexión
            </button>
            <div className="bg-slate-100 text-slate-400 px-8 py-4 rounded-2xl font-bold flex items-center gap-2">
                <TriangleAlert className="w-5 h-5" />
                Variable no detectada
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 pb-12 animate-in fade-in duration-700">
      {/* Search & Triage Header */}
      <div className="bg-gradient-to-br from-slate-900 via-indigo-950 to-slate-900 text-white p-10 md:p-16 rounded-[3rem] shadow-2xl border border-indigo-500/30 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none rotate-12 translate-x-12 -translate-y-12">
            <BrainCircuit className="w-96 h-96" />
        </div>

        <div className="relative z-10 max-w-4xl">
            <div className="flex items-center gap-3 mb-6">
              <span className="bg-indigo-500/20 text-indigo-300 text-[11px] font-black uppercase tracking-[0.3em] px-4 py-1.5 rounded-full border border-indigo-500/30 backdrop-blur-md">
                SATI ENGINE v4.2 PRO
              </span>
            </div>
            <h2 className="text-4xl md:text-5xl font-black mb-6 flex items-center gap-4 tracking-tighter">
                <Zap className="w-12 h-12 text-amber-400 fill-amber-400" />
                Intelligence Hub
            </h2>
            <p className="text-slate-400 mb-10 text-xl leading-relaxed max-w-2xl font-medium">
                Sistemas de triaje inteligente para fuentes abiertas y síntesis estratégica de amenazas en tiempo real.
            </p>

            <form 
              onSubmit={(e) => { e.preventDefault(); handleAnalizar(urlInput); }}
              className="flex flex-col md:flex-row gap-4"
            >
                <div className="relative flex-1 group">
                    <Globe className="absolute left-6 top-1/2 -translate-y-1/2 w-6 h-6 text-slate-500 group-focus-within:text-amber-500 transition-colors" />
                    <input 
                        type="url"
                        placeholder="Pega una URL (DarkReading, BleepingComputer, CVE...)"
                        value={urlInput}
                        onChange={(e) => setUrlInput(e.target.value)}
                        className="w-full pl-16 pr-8 py-6 bg-slate-800/40 border-2 border-slate-700/50 rounded-3xl focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 outline-none text-slate-100 placeholder:text-slate-600 transition-all font-bold backdrop-blur-lg"
                        required
                    />
                </div>
                <button 
                    type="submit"
                    disabled={analyzing || !urlInput}
                    className="px-12 py-6 bg-amber-500 hover:bg-amber-600 text-slate-950 font-black rounded-3xl shadow-2xl shadow-amber-500/40 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
                >
                    {analyzing ? <Loader2 className="w-7 h-7 animate-spin" /> : <Search className="w-7 h-7" />}
                    Analizar Fuente
                </button>
            </form>
        </div>
      </div>

      {/* AI Brief Section */}
      <div className="bg-white rounded-[3rem] border border-indigo-50 shadow-2xl shadow-indigo-100/50 overflow-hidden">
        <div className="p-8 md:p-10 border-b border-indigo-50 flex flex-col md:flex-row justify-between items-center gap-6 bg-slate-50/50">
          <div className="flex items-center gap-4">
            <div className="bg-indigo-600 p-3 rounded-2xl shadow-lg shadow-indigo-200">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
            <div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Brief Ejecutivo Diario</h3>
              <p className="text-sm text-slate-500 font-bold uppercase tracking-wider mt-1">SINTETIZADO POR SATI IA</p>
            </div>
          </div>
          <button 
            onClick={handleGenerateBrief}
            disabled={summarizing || items.length === 0}
            className="w-full md:w-auto flex items-center justify-center gap-3 px-8 py-4 bg-indigo-600 text-white rounded-2xl text-base font-black hover:bg-indigo-700 transition-all disabled:opacity-50 shadow-xl shadow-indigo-100"
          >
            {summarizing ? <Loader2 className="w-5 h-5 animate-spin" /> : <BookOpenCheck className="w-5 h-5" />}
            {summary ? 'Actualizar Análisis' : 'Generar Daily Brief'}
          </button>
        </div>

        <div className="p-8 md:p-12">
          {summarizing ? (
            <div className="flex flex-col items-center justify-center py-20 gap-6">
              <div className="relative">
                <div className="w-20 h-20 border-8 border-indigo-50 border-t-indigo-500 rounded-full animate-spin"></div>
                <Sparkles className="w-8 h-8 text-indigo-400 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
              </div>
              <p className="text-slate-500 font-black text-xl italic animate-pulse">Destilando inteligencia estratégica...</p>
            </div>
          ) : summary ? (
            <div className="prose prose-indigo prose-lg max-w-none animate-in fade-in duration-1000">
              <div 
                className="bg-slate-50/50 p-10 md:p-14 rounded-[2.5rem] border-2 border-slate-100 font-sans text-slate-800 leading-relaxed shadow-inner"
                dangerouslySetInnerHTML={{ __html: renderMarkdown(summary) }}
              />
            </div>
          ) : (
            <div className="text-center py-20 text-slate-400 bg-slate-50 rounded-[2.5rem] border-4 border-dashed border-slate-100">
              <Sparkles className="w-20 h-20 mx-auto mb-6 opacity-20" />
              <p className="font-black text-xl text-slate-400">El Daily Brief sintetiza los feeds globales para priorizar tu defensa.</p>
            </div>
          )}
        </div>
      </div>

      {/* Discovery Feed Section */}
      <div className="space-y-8">
        <div className="flex justify-between items-center px-4">
            <div className="flex items-center gap-4">
              <h3 className="text-3xl font-black text-slate-800 tracking-tighter flex items-center gap-4">
                  <Flame className="w-8 h-8 text-orange-500 fill-orange-500" />
                  CTI Observatory
              </h3>
              <span className="hidden md:inline-block bg-emerald-50 text-emerald-600 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] border border-emerald-100">
                Live Feed
              </span>
            </div>
            <div className="flex items-center gap-2 bg-slate-100 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
              <button 
                onClick={() => setViewMode('grid')}
                className={`p-3 rounded-xl transition-all ${viewMode === 'grid' ? 'bg-white shadow-md text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <LayoutGrid className="w-5 h-5" />
              </button>
              <button 
                onClick={() => setViewMode('list')}
                className={`p-3 rounded-xl transition-all ${viewMode === 'list' ? 'bg-white shadow-md text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <List className="w-5 h-5" />
              </button>
              <div className="w-px h-6 bg-slate-200 mx-2"></div>
              <button 
                onClick={loadData}
                disabled={loading}
                className="p-3 text-slate-500 hover:text-indigo-600 transition-colors"
              >
                <RefreshCw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
              </button>
            </div>
        </div>

        {loading ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {[1,2,3,4,5,6].map(i => (
                  <div key={i} className="bg-white h-72 rounded-[2.5rem] animate-pulse border border-slate-100 shadow-sm"></div>
                ))}
            </div>
        ) : error ? (
            <div className="p-16 bg-red-50 text-red-700 rounded-[3rem] border-2 border-red-100 text-center shadow-xl">
                <AlertCircle className="w-16 h-16 mx-auto mb-6 text-red-400" />
                <p className="font-black text-2xl mb-2">{error}</p>
                <p className="text-red-500 mb-8 font-medium">No se pudo recuperar el feed de inteligencia global.</p>
                <button onClick={loadData} className="px-10 py-4 bg-red-100 hover:bg-red-200 text-red-700 font-black rounded-2xl transition-all shadow-lg active:scale-95">Reintentar Sincronización</button>
            </div>
        ) : (
            <div className={viewMode === 'grid' ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8" : "space-y-6"}>
                {items.map((item, idx) => (
                    <div key={idx} className={`bg-white rounded-[2.5rem] border-2 border-slate-100 overflow-hidden hover:shadow-3xl hover:border-indigo-300 transition-all flex flex-col group relative ${viewMode === 'list' ? 'flex-row items-center gap-8 p-6' : ''}`}>
                        <div className={viewMode === 'grid' ? "p-8 flex-1" : "flex-1"}>
                            <div className="flex justify-between items-center mb-6">
                                <span className="px-3.5 py-1.5 bg-slate-50 text-slate-600 text-[10px] font-black uppercase rounded-xl tracking-[0.1em] border border-slate-100">
                                    {item.feedTitle}
                                </span>
                                <div className="flex items-center gap-2 text-[10px] text-slate-400 font-black uppercase">
                                  <Clock className="w-3.5 h-3.5" />
                                  {new Date(item.pubDate).toLocaleDateString()}
                                </div>
                            </div>
                            <h4 className="font-black text-slate-900 leading-tight mb-4 line-clamp-2 group-hover:text-indigo-600 transition-colors text-xl tracking-tight">
                                {item.title}
                            </h4>
                            <p className="text-base text-slate-500 line-clamp-2 leading-relaxed font-medium mb-6">
                                {item.description?.replace(/<[^>]*>?/gm, '') || 'Resumen técnico no disponible para esta entrada.'}
                            </p>
                        </div>
                        <div className={viewMode === 'grid' ? "px-8 py-6 bg-slate-50/50 border-t border-slate-100 flex items-center justify-between" : "flex flex-col gap-3 min-w-[180px]"}>
                            <a 
                              href={item.link} 
                              target="_blank" 
                              rel="noreferrer" 
                              className="text-slate-400 hover:text-indigo-600 p-3 hover:bg-white rounded-2xl transition-all shadow-inner"
                              title="Ver Fuente Original"
                            >
                                <ExternalLink className="w-6 h-6" />
                            </a>
                            <button 
                                onClick={() => handleAnalizar(item.link, item)}
                                className="px-6 py-3 bg-slate-900 text-white text-[12px] font-black rounded-2xl hover:bg-indigo-600 transition-all flex items-center gap-3 shadow-2xl active:scale-95"
                            >
                                <Zap className="w-4 h-4 text-amber-400 fill-amber-400" />
                                Triaje IA
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        )}
      </div>

      {/* Triage Review Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-950/90 z-50 flex items-center justify-center p-4 backdrop-blur-xl animate-in fade-in duration-300">
            <div className="bg-white rounded-[3.5rem] shadow-3xl w-full max-w-5xl max-h-[95vh] flex flex-col animate-in zoom-in duration-500 overflow-hidden border border-slate-100">
                <div className="flex justify-between items-center p-8 md:p-12 border-b border-slate-100 bg-slate-50/30">
                    <div className="flex items-center gap-6">
                        <div className="bg-amber-500 p-5 rounded-[2rem] shadow-2xl shadow-amber-500/30">
                            <BrainCircuit className="w-10 h-10 text-white" />
                        </div>
                        <div>
                            <h3 className="text-3xl font-black text-slate-900 tracking-tighter">SATI Triage Engine</h3>
                            <div className="flex items-center gap-3 mt-2">
                                <span className={`text-[11px] font-black uppercase px-4 py-1.5 rounded-full border-2 ${analyzing ? 'bg-amber-50 text-amber-700 border-amber-200 animate-pulse' : 'bg-emerald-50 text-emerald-700 border-emerald-200'}`}>
                                    {analyzing ? 'Procesando Semántica...' : 'Inteligencia Clasificada'}
                                </span>
                            </div>
                        </div>
                    </div>
                    {!analyzing && (
                        <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-900 p-4 hover:bg-slate-100 rounded-full transition-all">
                            <X className="w-10 h-10" />
                        </button>
                    )}
                </div>

                <div className="flex-1 overflow-y-auto p-8 md:p-16 bg-slate-50/20">
                    {analyzing ? (
                        <div className="h-full flex flex-col items-center justify-center text-center py-20 animate-in fade-in duration-500">
                            <div className="relative mb-12">
                                <div className="w-40 h-40 border-[10px] border-amber-100 border-t-amber-500 rounded-full animate-spin"></div>
                                <Zap className="w-16 h-16 text-amber-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 fill-current drop-shadow-2xl" />
                            </div>
                            <h4 className="text-4xl font-black text-slate-900 mb-4 tracking-tight">Análisis Neuronal</h4>
                            <p className="text-slate-500 max-w-sm mx-auto text-xl leading-relaxed font-medium">Gemini está mapeando la inteligencia técnica a los esquemas de SATI...</p>
                        </div>
                    ) : formData ? (
                        <div className="space-y-12">
                            {formData.error ? (
                                <div className="p-16 text-center text-red-500 bg-red-50 rounded-[3rem] border-2 border-red-100 shadow-xl">
                                    <AlertCircle className="w-20 h-20 mx-auto mb-6 text-red-400" />
                                    <p className="font-black text-2xl">{formData.error}</p>
                                </div>
                            ) : (
                                <>
                                    <div className="flex items-center justify-between bg-white p-6 rounded-3xl border-2 border-slate-100 shadow-xl shadow-slate-200/50">
                                        <div className="flex items-center gap-4">
                                            <div className="p-3 bg-emerald-100 rounded-2xl shadow-inner">
                                                <CheckCircle2 className="w-8 h-8 text-emerald-600" />
                                            </div>
                                            <h4 className="font-black text-slate-800 uppercase tracking-widest text-base">
                                              Clasificación Automática: <span className="text-indigo-600 font-black">{detectedType?.toUpperCase()}</span>
                                            </h4>
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10 bg-white p-10 md:p-16 rounded-[3rem] border-2 border-slate-100 shadow-3xl shadow-slate-200/30 relative overflow-hidden">
                                        <div className="absolute top-0 left-0 w-4 h-full bg-indigo-500"></div>
                                        {Object.keys(formData).map((key) => (
                                            <div key={key} className={key === 'descripcion' ? 'md:col-span-2' : ''}>
                                                <label className="block text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] mb-4 ml-1">
                                                    {key.replace(/([A-Z])/g, ' $1').trim()}
                                                </label>
                                                {key === 'descripcion' ? (
                                                    <textarea 
                                                        value={formData[key]}
                                                        onChange={(e) => handleFieldChange(key, e.target.value)}
                                                        className="w-full p-6 bg-slate-50 border-2 border-slate-100 rounded-3xl text-lg font-semibold text-slate-700 focus:ring-8 focus:ring-amber-500/10 focus:border-amber-500 focus:bg-white outline-none min-h-[220px] transition-all resize-none shadow-inner"
                                                    />
                                                ) : (
                                                    <input 
                                                        type={key === 'fecha' ? 'date' : (typeof formData[key] === 'number' ? 'number' : 'text')}
                                                        value={formData[key]}
                                                        onChange={(e) => handleFieldChange(key, e.target.value)}
                                                        className="w-full p-6 bg-slate-50 border-2 border-slate-100 rounded-3xl text-lg font-black text-slate-800 focus:ring-8 focus:ring-amber-500/10 focus:border-amber-500 focus:bg-white outline-none transition-all shadow-inner"
                                                    />
                                                )}
                                            </div>
                                        ))}
                                    </div>

                                    <div className="bg-slate-900 p-10 rounded-[3rem] flex items-start gap-8 shadow-3xl">
                                        <ShieldAlert className="w-14 h-14 text-amber-500 mt-2 flex-shrink-0" />
                                        <div>
                                            <p className="font-black text-white text-2xl mb-3 tracking-tight">Validación de Analista</p>
                                            <p className="text-slate-400 text-lg leading-relaxed font-medium">
                                              Confirma la exactitud de los datos estructurados por la IA antes de proceder con el registro en el repositorio central de inteligencia estratégica.
                                            </p>
                                        </div>
                                    </div>
                                </>
                            )}
                        </div>
                    ) : null}
                </div>

                <div className="p-10 md:p-12 border-t border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-8">
                    <div className="flex items-center gap-4 text-xs font-black text-slate-400 uppercase tracking-[0.2em]">
                        <FileJson className="w-7 h-7 text-indigo-500" />
                        ENGINE_ID: {Math.random().toString(36).substring(7).toUpperCase()}
                    </div>
                    <div className="flex gap-6 w-full md:w-auto">
                        <button 
                            onClick={() => setShowModal(false)}
                            className="flex-1 md:flex-none px-12 py-5 text-slate-500 font-black hover:bg-slate-50 rounded-[1.5rem] transition-all border-2 border-slate-100 hover:border-slate-200 active:scale-95"
                        >
                            Ignorar
                        </button>
                        <button 
                            onClick={handleSaveResource}
                            disabled={isSaving || !formData || formData.error}
                            className="flex-1 md:flex-none px-16 py-5 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-[1.5rem] shadow-3xl shadow-indigo-400/50 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50"
                        >
                            {isSaving ? <Loader2 className="w-6 h-6 animate-spin" /> : <Save className="w-6 h-6" />}
                            Registrar Intel
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

