export const askAI = async (query: string): Promise<{ response: string }> => {
  try {
    const res = await fetch(`${API_BASE_URL}/ai/analyze`, {
      method: 'POST',
      headers: getAuthHeaders(),
      body: JSON.stringify({ query })
    });
    const result = await handleResponse(res);
    if (result.success) return result.data as { response: string };
    throw new Error(result.message);
  } catch (error: any) {
    throw new Error(error.message || 'Error al conectar con el Analista IA');
  }
};

/**
 * Genera un brief estratégico utilizando Gemini Flash
 */
export const generateStrategicBriefAI = async (newsItems: NewsItem[]) => {
  const apiKey = getSafeApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");

  const ai = new GoogleGenAI({ apiKey });
  const newsContent = newsItems.slice(0, 10).map(item => `- [${item.feedTitle}] ${item.title}: ${item.description?.substring(0, 150)}`).join('\n');

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Act like a Senior CTI Analyst. Summarize the following news list into a concise executive daily brief in Spanish. Focus on emerging threats, critical vulnerabilities, and global campaigns. Use markdown with sections for "Top Threats", "Vulnerabilities", and "Recommended Actions".\n\nNews:\n${newsContent}`,
  });

  return response.text;
};

/**
 * Realiza un triaje inteligente de una fuente (URL o texto) para clasificarla en el esquema de SATI
 */
export const performIntelligenceTriageAI = async (url: string, context: string) => {
  const apiKey = getSafeApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");

  const ai = new GoogleGenAI({ apiKey });
  const prompt = `Act as a CTI Triage Engine. Analyze this intelligence source and map it to one of these types: 'incidente', 'exploit', 'zeroday', 'cve', or 'alerta'. 
  Return ONLY a JSON object with two fields: "type" (one of the strings above) and "data" (the mapped object following these rules:
  - incidente: { fecha (YYYY-MM-DD), tipo, entidad, pais, sector, descripcion, actor, url }
  - exploit: { fecha, nombre, tipo, plataforma, cve, url }
  - zeroday: { idZD, fecha, nombre, plataforma, cvss, estado, url, descripcion }
  - cve: { cveId, fecha, aplicativo, cvss, estado, descripcion, url }
  - alerta: { titulo, descripcion, criticidad (Baja/Media/Alta/Critica), fecha, url }
  )
  Context:\n${context}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: { responseMimeType: "application/json" }
  });

  if (!response.text) throw new Error("AI_EMPTY_RESPONSE");
  return JSON.parse(response.text);
};

