                        <div>
                            <h3 className="text-4xl font-black text-slate-900 tracking-tighter">SATI Triage Engine</h3>
                            <div className="flex items-center gap-4 mt-3">
                                <span className={`text-[12px] font-black uppercase px-5 py-2 rounded-full border-2 ${analyzing ? 'bg-amber-50 text-amber-700 border-amber-200 animate-pulse' : 'bg-emerald-50 text-emerald-700 border-emerald-200 shadow-sm shadow-emerald-50'}`}>
                                    {analyzing ? 'Procesando Semántica Neuronal...' : 'Inteligencia Clasificada'}
                                </span>
                            </div>
                        </div>
                    </div>
                    {!analyzing && (
                        <button onClick={() => setShowModal(false)} className="text-slate-300 hover:text-slate-900 p-5 hover:bg-slate-100 rounded-full transition-all">
                            <X className="w-12 h-12" />
                        </button>
                    )}
                </div>

                <div className="flex-1 overflow-y-auto p-10 md:p-20 bg-slate-50/10">
                    {analyzing ? (
                        <div className="h-full flex flex-col items-center justify-center text-center py-24 animate-in fade-in duration-500">
                            <div className="relative mb-14">
                                <div className="w-48 h-48 border-[12px] border-amber-50 border-t-amber-500 rounded-full animate-spin"></div>
                                <Zap className="w-20 h-20 text-amber-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 fill-current drop-shadow-3xl" />
                            </div>
                            <h4 className="text-5xl font-black text-slate-900 mb-5 tracking-tighter">Análisis Neuronal</h4>
                            <p className="text-slate-500 max-w-md mx-auto text-2xl leading-relaxed font-medium">Gemini está mapeando la inteligencia técnica según los esquemas de SATI...</p>
                        </div>
                    ) : formData ? (
                        <div className="space-y-14">
                            {formData.error ? (
                                <div className="p-20 text-center text-red-500 bg-red-50 rounded-[4rem] border-2 border-red-100 shadow-2xl">
                                    <AlertCircle className="w-24 h-24 mx-auto mb-8 text-red-400" />
                                    <p className="font-black text-3xl tracking-tighter">{formData.error}</p>
                                </div>
                            ) : (
                                <>
                                    <div className="flex items-center justify-between bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-2xl shadow-slate-200/50">
                                        <div className="flex items-center gap-5">
                                            <div className="p-4 bg-emerald-100 rounded-3xl shadow-inner">
                                                <CheckCircle2 className="w-10 h-10 text-emerald-600" />
                                            </div>
                                            <h4 className="font-black text-slate-800 uppercase tracking-widest text-lg">
                                              Clasificación Automática: <span className="text-indigo-600 font-black">{detectedType?.toUpperCase()}</span>
                                            </h4>
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-12 bg-white p-12 md:p-20 rounded-[4rem] border-2 border-slate-100 shadow-4xl shadow-slate-200/30 relative overflow-hidden">
                                        <div className="absolute top-0 left-0 w-5 h-full bg-indigo-500"></div>
                                        {Object.keys(formData).map((key) => (
                                            <div key={key} className={key === 'descripcion' ? 'md:col-span-2' : ''}>
                                                <label className="block text-[12px] font-black text-slate-400 uppercase tracking-[0.4em] mb-5 ml-2">
                                                    {key.replace(/([A-Z])/g, ' $1').trim()}
                                                </label>
                                                {key === 'descripcion' ? (
                                                    <textarea 
                                                        value={formData[key]}
                                                        onChange={(e) => handleFieldChange(key, e.target.value)}
                                                        className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] text-xl font-semibold text-slate-700 focus:ring-[16px] focus:ring-amber-500/5 focus:border-amber-500 focus:bg-white outline-none min-h-[250px] transition-all resize-none shadow-inner"
                                                    />
                                                ) : (
                                                    <input 
                                                        type={key === 'fecha' ? 'date' : (typeof formData[key] === 'number' ? 'number' : 'text')}
                                                        value={formData[key]}
                                                        onChange={(e) => handleFieldChange(key, e.target.value)}
                                                        className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] text-xl font-black text-slate-800 focus:ring-[16px] focus:ring-amber-500/5 focus:border-amber-500 focus:bg-white outline-none transition-all shadow-inner"
                                                    />
                                                )}
                                            </div>
                                        ))}
                                    </div>

                                    <div className="bg-slate-900 p-12 rounded-[4rem] flex items-start gap-10 shadow-4xl">
                                        <ShieldAlert className="w-20 h-20 text-amber-500 mt-2 flex-shrink-0" />
                                        <div>
                                            <p className="font-black text-white text-3xl mb-4 tracking-tighter">Validación de Analista Requerida</p>
                                            <p className="text-slate-400 text-xl leading-relaxed font-medium">
                                              Confirma la precisión de los datos estructurados por la IA antes de proceder con el registro en el repositorio central de inteligencia estratégica de la organización.
                                            </p>
                                        </div>
                                    </div>
                                </>
                            )}
                        </div>
                    ) : null}
                </div>

                <div className="p-12 md:p-16 border-t border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-10">
                    <div className="flex items-center gap-5 text-sm font-black text-slate-400 uppercase tracking-[0.3em]">
                        <FileJson className="w-10 h-10 text-indigo-500" />
                        ENGINE_ID: {Math.random().toString(36).substring(7).toUpperCase()}
                    </div>
                    <div className="flex gap-8 w-full md:w-auto">
                        <button 
                            onClick={() => setShowModal(false)}
                            className="flex-1 md:flex-none px-14 py-6 text-slate-500 font-black hover:bg-slate-50 rounded-[2rem] transition-all border-2 border-slate-100 hover:border-slate-200 active:scale-95 text-lg"
                        >
                            Ignorar
                        </button>
                        <button 
                            onClick={handleSaveResource}
                            disabled={isSaving || !formData || formData.error}
                            className="flex-1 md:flex-none px-20 py-6 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-[2rem] shadow-4xl shadow-indigo-400/50 transition-all flex items-center justify-center gap-5 active:scale-95 disabled:opacity-50 text-lg"
                        >
                            {isSaving ? <Loader2 className="w-8 h-8 animate-spin" /> : <Save className="w-8 h-8" />}
                            Registrar Inteligencia
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};
